#include<bits/stdc++.h>
using namespace std;
long long b[1011][1011];
long long a[1011][1011];
long long maxx=-1e7,x,y;
int main() {
	int n, m, c;
	cin >> n >> m >> c;
	for (int i = 1; i <= n; i++) {
		for (int j = 1; j <= n; j++) {
			cin >> b[i][j];
			a[i][j] = a[i][j - 1] + b[i][j];
		}
	}
	for (int i = 1; i <= n; i++) {
		for (int j = 1; j <= n; j++) {
			a[i][j] = a[i - 1][j] + a[i][j];
		}
	}
	for (int i = c; i <= n; i++) {
		for (int j = c; j <= n; j++) {
			if(maxx<(a[i][j]+a[i-c][j-c]-a[i-c][j]-a[i][j-c])){
				x=i-c+1;
				y=j-c+1;
				maxx=a[i][j]+a[i-c][j-c]-a[i-c][j]-a[i][j-c];
			}
		}
	}
	cout<<x<<' '<<y;
	return 0;
}
